const req = $input.item.json;
let code = '';
if (req.query && req.query.code) {
  code = req.query.code;
} else {
  const url = req.headers && req.headers['x-original-url'] ? req.headers['x-original-url'] : (req.url || '');
  const parts = url.split('/');
  const lastPart = parts[parts.length - 1];
  code = lastPart ? lastPart.split('?')[0] : '';
}
code = decodeURIComponent(code).trim();
if (!code || code === 'item' || code === 'undefined') {
  return { json: { _error: true, success: false, message: '请提供物料编号' } };
}
// 安全: SAP物料号白名单 (字母/数字/连字符/下划线/点/空格, 最长50字符)
if (!/^[A-Za-z0-9\-_.\/ ]{1,50}$/.test(code)) {
  return { json: { _error: true, success: false, message: '物料编号格式无效: ' + code.substring(0, 20) } };
}
// 安全加固: 纵深防御，移除潜在危险字符
code = code.replace(/['"\\;]/g, '');
return { json: { _error: false, code: code } };

const item = $input.first().json;
return { json: {
  success: true,
  item: {
    itemCode: item.item_code,
    itemName: item.item_name || '',
    uom: item.uom || '',
    barcode: '',
    onHand: 0,
    committed: 0,
    onOrder: 0,
    source: 'cache'
  }
}};

const rows = $input.all();
const r = (rows && rows.length > 0 && rows[0].json) ? rows[0].json : null;
if (!r || !r.ItemCode) {
  return { json: { success: false, message: '未找到该物料' } };
}
return { json: {
  success: true,
  item: {
    itemCode: r.ItemCode,
    itemName: r.ItemName || '',
    uom: r.uom || '',
    barcode: r.barcode || '',
    onHand: parseFloat(r.onHand) || 0,
    committed: parseFloat(r.committed) || 0,
    onOrder: parseFloat(r.onOrder) || 0,
    source: 'sap'
  }
}};

// V20: 参数化查询重构 — 消除 SQL 注入风险
const req = $input.item.json;
const docType = (req.query && req.query.type) ? req.query.type : '';
const ids = (req.query && req.query.ids) ? req.query.ids : '';
// ids 仍然做数字过滤作为额外防护层
const safeIds = ids ? ids.replace(/[^0-9,]/g, '') : '';
return { json: { docType: docType, idList: safeIds } };

const rows = $input.all();
const headers = ['doc_type', 'doc_number', 'sap_doc_num', 'warehouse_code', 'wms_status', 'doc_date', 'created_by', 'line_num', 'item_code', 'item_name', 'uom', 'planned_qty', 'actual_qty', 'bin_location', 'direction', 'batch_number', 'serial_number', 'operator', 'transaction_time'];
const csvLines = [headers.join(',')];
let dataCount = 0;
const esc = (v) => { if (v === null || v === undefined) v = ''; return '"' + String(v).replace(/"/g, '""') + '"'; };
for (const row of rows) {
  const r = row.json;
  if (!r || !r.doc_type) continue;
  if ((r.doc_type === 'LM' || r.doc_type === 'TR') && (r.tx_from_bin || r.tx_from_warehouse)) {
    // LM/TR借贷拆分: 贷行(出) + 借行(入)
    const fromWhs = r.tx_from_warehouse || r.warehouse_code || ''; const toWhs = r.tx_warehouse_code || r.warehouse_code || ''; const base = [esc(r.doc_type), esc(r.doc_number), esc(r.sap_doc_num), esc(fromWhs), esc(r.wms_status), esc(r.doc_date), esc(r.created_by), esc(r.line_num), esc(r.item_code), esc(r.item_name), esc(r.uom), esc(r.planned_qty)];
    const txQty = Number(r.tx_qty) || Number(r.actual_qty) || 0;
    // 贷行(出): 负数, 源库位
    csvLines.push([...base, esc(-txQty), esc(r.tx_from_bin), esc('贷(出)'), esc(r.batch_number), esc(r.serial_number), esc(r.tx_operator || r.created_by), esc(r.transaction_time)].join(','));
    dataCount++;
    // 借行(入): 正数, 目标库位
    csvLines.push([...base.slice(0, 3), esc(toWhs), ...base.slice(4), esc(txQty), esc(r.tx_to_bin || r.bin_location || ''), esc('借(入)'), esc(r.batch_number), esc(r.serial_number), esc(r.tx_operator || r.created_by), esc(r.transaction_time)].join(','));
    dataCount++;
  } else {
    // V17.1: 非LM类型 — 有transaction时用tx_qty(单次数量), 无transaction时用actual_qty(行累计)
    const qty = (r.tx_qty !== null && r.tx_qty !== undefined) ? r.tx_qty : r.actual_qty;
    const line = [esc(r.doc_type), esc(r.doc_number), esc(r.sap_doc_num), esc(r.warehouse_code), esc(r.wms_status), esc(r.doc_date), esc(r.created_by), esc(r.line_num), esc(r.item_code), esc(r.item_name), esc(r.uom), esc(r.planned_qty), esc(qty), esc(r.bin_location), esc(''), esc(r.batch_number), esc(r.serial_number), esc(r.tx_operator || r.created_by), esc(r.transaction_time)];
    csvLines.push(line.join(','));
    dataCount++;
  }
}
return { json: { csv: '\uFEFF' + csvLines.join('\n'), count: dataCount } };

const row = $input.first().json;
return { json: {
  success: true,
  stats: {
    today_transactions: parseInt(row.today_transactions) || 0,
    in_progress: parseInt(row.in_progress) || 0,
    today_completed: parseInt(row.today_completed) || 0,
    pending_export: parseInt(row.pending_export) || 0
  },
  sync_status: {
    has_yesterday_snapshot: parseInt(row.yesterday_snapshot_count) > 0,
    items_sync_hours_ago: parseFloat(row.items_sync_hours_ago) || 9999,
    locations_sync_hours_ago: parseFloat(row.locations_sync_hours_ago) || 9999,
    bins_sync_hours_ago: parseFloat(row.bins_sync_hours_ago) || 9999
  }
}};

// V2: 比较 SAP 更新日期 vs PG 同步日期 (含 OMS + 库存窗口修复)
const sapData = $('SAP查询更新日期').first().json;
const pgData = $input.first().json;

function needSync(sapDate, pgSynced) {
  if (!sapDate) return false;
  if (!pgSynced) return true;
  return new Date(sapDate) > new Date(pgSynced);
}

// 库存: 最新快照日期 < 昨天 → 需要同步
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayStr = yesterday.toISOString().split('T')[0];

return { json: {
  success: true,
  items: {
    need_sync: needSync(sapData.sap_items_date, pgData.pg_items_synced),
    sap_date: sapData.sap_items_date || null,
    pg_synced: pgData.pg_items_synced || null
  },
  locations: {
    need_sync: needSync(sapData.sap_locations_date, pgData.pg_locations_synced),
    sap_date: sapData.sap_locations_date || null,
    pg_synced: pgData.pg_locations_synced || null
  },
  bins: {
    need_sync: needSync(sapData.sap_bins_date, pgData.pg_bins_synced),
    sap_date: sapData.sap_bins_date || null,
    pg_synced: pgData.pg_bins_synced || null
  },
  stock: {
    need_sync: !pgData.latest_snapshot_date || pgData.latest_snapshot_date < yesterdayStr,
    latest_snapshot: pgData.latest_snapshot_date || null,
    snapshot_count: parseInt(pgData.snapshot_count) || 0
  },
  oms: {
    need_sync: needSync(sapData.sap_oms_date, pgData.pg_oms_synced),
    sap_date: sapData.sap_oms_date || null,
    pg_synced: pgData.pg_oms_synced || null
  }
}};
